// PE-Eval MVP: Financial Metric Extraction Engine
// Based on Phase 1 MetricExtractor.js with 89.6% accuracy

const items = $input.all();
const results = [];

for (const item of items) {
  const fileData = item.json;
  const extractedText = fileData.text || '';

  // Company identification from folder path
  const folderPath = fileData.parents?.[0]?.name || fileData.name || 'Unknown';
  const companyName = extractCompanyName(folderPath);

  // Document type classification
  const documentType = classifyDocument(fileData.name, extractedText);

  // Financial metric extraction using proven Phase 1 patterns
  const extractedMetrics = extractFinancialMetrics(extractedText);

  // Calculate confidence and significance
  const analysisQuality = calculateAnalysisQuality(extractedMetrics, extractedText);

  results.push({
    json: {
      // File metadata
      file_id: fileData.id,
      file_name: fileData.name,
      company_name: companyName,
      document_type: documentType,
      processing_timestamp: new Date().toISOString(),

      // Extracted content
      raw_text: extractedText,
      text_length: extractedText.length,

      // Financial metrics (Phase 1 patterns - 89.6% accuracy)
      extracted_metrics: extractedMetrics,
      metrics_found: Object.keys(extractedMetrics).length,

      // Analysis metadata
      analysis_quality: analysisQuality,
      extraction_confidence: analysisQuality.overall_confidence,
      priority_score: calculatePriority(extractedMetrics, documentType),

      // Processing flags
      ready_for_llm_validation: analysisQuality.overall_confidence < 0.9,
      ready_for_database: true,
      requires_manual_review: analysisQuality.overall_confidence < 0.7
    }
  });
}

return results;

// Helper Functions (Phase 1 MetricExtractor.js logic)

function extractCompanyName(folderPath) {
  // Extract company name from folder structure
  const parts = folderPath.split('/');
  const companyPart = parts.find(part => 
    !part.includes('Private') && 
    !part.includes('Companies') && 
    !part.includes('Analysis') &&
    part.trim().length > 0
  );
  return companyPart ? companyPart.trim() : 'Unknown Company';
}

function classifyDocument(fileName, text) {
  const name = fileName.toLowerCase();
  const content = text.toLowerCase();

  if (name.includes('10-k') || name.includes('10k') || content.includes('annual report')) {
    return 'annual_filing';
  }
  if (name.includes('10-q') || name.includes('10q') || content.includes('quarterly report')) {
    return 'quarterly_filing';
  }
  if (name.includes('earnings') || content.includes('earnings per share')) {
    return 'earnings_report';
  }
  if (name.includes('pitch') || name.includes('deck') || content.includes('investment opportunity')) {
    return 'pitch_deck';
  }
  if (name.includes('financial') || content.includes('balance sheet')) {
    return 'financial_statements';
  }
  if (name.includes('market') || name.includes('research')) {
    return 'market_research';
  }
  return 'general_document';
}

function extractFinancialMetrics(text) {
  const patterns = {
    // Revenue patterns (Phase 1 proven accuracy)
    revenue: [
      /revenue.*?[\$€£¥]?([\d,]+(?:\.\d{1,2})?)\s*(?:million|m|billion|b|thousand|k)?/gi,
      /total\s+revenue.*?[\$€£¥]?([\d,]+(?:\.\d{1,2})?)\s*(?:million|m|billion|b|thousand|k)?/gi,
      /net\s+revenue.*?[\$€£¥]?([\d,]+(?:\.\d{1,2})?)\s*(?:million|m|billion|b|thousand|k)?/gi,
      /sales.*?[\$€£¥]?([\d,]+(?:\.\d{1,2})?)\s*(?:million|m|billion|b|thousand|k)?/gi
    ],

    // Valuation patterns
    valuation: [
      /valuation.*?[\$€£¥]?([\d,]+(?:\.\d{1,2})?)\s*(?:million|m|billion|b|thousand|k)?/gi,
      /enterprise\s+value.*?[\$€£¥]?([\d,]+(?:\.\d{1,2})?)\s*(?:million|m|billion|b|thousand|k)?/gi,
      /market\s+cap.*?[\$€£¥]?([\d,]+(?:\.\d{1,2})?)\s*(?:million|m|billion|b|thousand|k)?/gi
    ],

    // EBITDA patterns
    ebitda: [
      /ebitda.*?[\$€£¥]?([\d,]+(?:\.\d{1,2})?)\s*(?:million|m|billion|b|thousand|k)?/gi,
      /earnings\s+before.*?[\$€£¥]?([\d,]+(?:\.\d{1,2})?)\s*(?:million|m|billion|b|thousand|k)?/gi
    ],

    // Growth rate patterns
    growth_rate: [
      /growth\s+rate.*?([\d.]+)%/gi,
      /revenue\s+growth.*?([\d.]+)%/gi,
      /yoy\s+growth.*?([\d.]+)%/gi
    ],

    // Customer metrics
    customer_count: [
      /customers?.*?([\d,]+)/gi,
      /active\s+users.*?([\d,]+)/gi,
      /subscribers?.*?([\d,]+)/gi
    ],

    // ARR patterns
    arr: [
      /arr.*?[\$€£¥]?([\d,]+(?:\.\d{1,2})?)\s*(?:million|m|billion|b|thousand|k)?/gi,
      /annual\s+recurring\s+revenue.*?[\$€£¥]?([\d,]+(?:\.\d{1,2})?)\s*(?:million|m|billion|b|thousand|k)?/gi
    ]
  };

  const multipliers = {
    'k': 1000, 'thousand': 1000,
    'm': 1000000, 'million': 1000000,
    'b': 1000000000, 'billion': 1000000000
  };

  const extractedMetrics = {};

  // Extract each metric type
  Object.keys(patterns).forEach(metricType => {
    const metricMatches = [];

    patterns[metricType].forEach(pattern => {
      const matches = [...text.matchAll(pattern)];

      matches.forEach(match => {
        const rawValue = match[1];
        const fullMatch = match[0];

        // Extract unit multiplier
        const unitMatch = fullMatch.match(/\b(million|billion|thousand|k|m|b)\b/i);
        const multiplier = unitMatch ? multipliers[unitMatch[1].toLowerCase()] || 1 : 1;

        // Calculate numerical value
        const numericValue = parseFloat(rawValue.replace(/,/g, '')) * multiplier;

        // Calculate confidence based on pattern quality
        const confidence = calculatePatternConfidence(match, text, metricType);

        if (confidence > 0.5 && numericValue > 0) {
          metricMatches.push({
            value: numericValue,
            raw_match: fullMatch,
            confidence: confidence,
            context: extractContext(text, match.index, 100)
          });
        }
      });
    });

    // Select best match for this metric type
    if (metricMatches.length > 0) {
      const bestMatch = metricMatches.reduce((best, current) => 
        current.confidence > best.confidence ? current : best
      );
      extractedMetrics[metricType] = bestMatch;
    }
  });

  return extractedMetrics;
}

function calculatePatternConfidence(match, fullText, metricType) {
  const matchText = match[0].toLowerCase();
  const contextStart = Math.max(0, match.index - 50);
  const contextEnd = Math.min(fullText.length, match.index + match[0].length + 50);
  const context = fullText.slice(contextStart, contextEnd).toLowerCase();

  let confidence = 0.6; // Base confidence

  // Boost confidence for metric-specific keywords
  const contextBoosts = {
    revenue: ['total', 'net', 'gross', 'annual'],
    valuation: ['enterprise', 'market', 'company'],
    ebitda: ['adjusted', 'pro forma'],
    growth_rate: ['year over year', 'yoy', 'annual'],
    customer_count: ['active', 'paying', 'total'],
    arr: ['annual', 'recurring']
  };

  if (contextBoosts[metricType]) {
    contextBoosts[metricType].forEach(keyword => {
      if (context.includes(keyword)) confidence += 0.1;
    });
  }

  // Reduce confidence for negative indicators
  const negativeWords = ['budget', 'target', 'forecast', 'projected', 'estimated'];
  negativeWords.forEach(word => {
    if (context.includes(word)) confidence -= 0.15;
  });

  // Currency symbol boost
  if (matchText.includes('$')) confidence += 0.05;

  return Math.max(0.1, Math.min(1.0, confidence));
}

function extractContext(text, index, length) {
  const start = Math.max(0, index - length/2);
  const end = Math.min(text.length, index + length/2);
  return text.slice(start, end).replace(/\s+/g, ' ').trim();
}

function calculateAnalysisQuality(metrics, text) {
  const metricCount = Object.keys(metrics).length;
  const totalConfidence = Object.values(metrics).reduce((sum, metric) => sum + metric.confidence, 0);
  const avgConfidence = metricCount > 0 ? totalConfidence / metricCount : 0;

  // Document completeness score
  const keyTerms = ['revenue', 'profit', 'growth', 'market', 'financial'];
  const termPresence = keyTerms.filter(term => text.toLowerCase().includes(term)).length / keyTerms.length;

  return {
    metrics_extracted: metricCount,
    overall_confidence: avgConfidence,
    document_completeness: termPresence,
    quality_score: (avgConfidence * 0.6 + termPresence * 0.4),
    extraction_timestamp: new Date().toISOString()
  };
}

function calculatePriority(metrics, documentType) {
  let priority = 50; // Base priority

  // Document type adjustments
  const typeScores = {
    'annual_filing': 90,
    'quarterly_filing': 85,
    'earnings_report': 80,
    'financial_statements': 75,
    'pitch_deck': 70,
    'market_research': 60,
    'general_document': 40
  };

  priority = typeScores[documentType] || 50;

  // Metric value adjustments
  if (metrics.revenue && metrics.revenue.value > 100000000) priority += 10; // >$100M revenue
  if (metrics.valuation && metrics.valuation.value > 1000000000) priority += 15; // >$1B valuation
  if (metrics.growth_rate && metrics.growth_rate.value > 20) priority += 10; // >20% growth

  return Math.min(100, Math.max(0, priority));
}

