// PE-Eval MVP: Delta Intelligence Calculator
// Calculate metric changes from previous values in state database

const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  // Extract current metrics
  const currentMetrics = data.validated_metrics || data.extracted_metrics || {};

  // Initialize delta analysis
  const deltaAnalysis = {
    company_name: data.company_name,
    analysis_timestamp: new Date().toISOString(),
    metric_deltas: {},
    significant_changes: [],
    alert_triggers: []
  };

  // Calculate deltas for each metric (simplified for MVP)
  Object.keys(currentMetrics).forEach(metricType => {
    const currentValue = currentMetrics[metricType]?.value;

    if (currentValue && typeof currentValue === 'number') {
      // MVP: Placeholder for historical comparison
      // In Phase 2, this will query actual historical data
      const mockPreviousValue = currentValue * 0.85; // Simulated 15% growth

      const absoluteChange = currentValue - mockPreviousValue;
      const percentageChange = (absoluteChange / mockPreviousValue) * 100;

      deltaAnalysis.metric_deltas[metricType] = {
        current_value: currentValue,
        previous_value: mockPreviousValue,
        absolute_change: absoluteChange,
        percentage_change: percentageChange,
        significance: calculateSignificance(absoluteChange, percentageChange, metricType)
      };

      // Check for significant changes (alert thresholds)
      if (Math.abs(percentageChange) > 10 || (metricType === 'revenue' && Math.abs(absoluteChange) > 1000000)) {
        deltaAnalysis.significant_changes.push({
          metric: metricType,
          change: `${percentageChange > 0 ? '+' : ''}${percentageChange.toFixed(1)}%`,
          value_change: formatCurrency(absoluteChange),
          significance: deltaAnalysis.metric_deltas[metricType].significance
        });

        // Generate alert if significant
        if (Math.abs(percentageChange) > 20 || Math.abs(absoluteChange) > 5000000) {
          deltaAnalysis.alert_triggers.push({
            type: 'significant_change',
            metric: metricType,
            severity: Math.abs(percentageChange) > 30 ? 'critical' : 'high',
            message: `${data.company_name}: ${metricType} changed ${percentageChange > 0 ? '+' : ''}${percentageChange.toFixed(1)}% (${formatCurrency(absoluteChange)})`
          });
        }
      }
    }
  });

  results.push({
    json: {
      ...data,
      delta_analysis: deltaAnalysis,
      has_significant_changes: deltaAnalysis.significant_changes.length > 0,
      requires_immediate_alert: deltaAnalysis.alert_triggers.length > 0,
      delta_summary: generateDeltaSummary(deltaAnalysis)
    }
  });
}

return results;

// Helper functions
function calculateSignificance(absoluteChange, percentageChange, metricType) {
  const weights = {
    revenue: 1.0,
    valuation: 0.8,
    ebitda: 0.9,
    growth_rate: 0.7,
    customer_count: 0.6,
    arr: 0.85
  };

  const weight = weights[metricType] || 0.5;
  const percentageScore = Math.min(Math.abs(percentageChange) / 50, 1); // 50% = max score
  const magnitudeScore = Math.min(Math.abs(absoluteChange) / 10000000, 1); // $10M = max score

  return (percentageScore * 0.7 + magnitudeScore * 0.3) * weight;
}

function formatCurrency(value) {
  if (Math.abs(value) >= 1000000000) {
    return `$${(value / 1000000000).toFixed(1)}B`;
  } else if (Math.abs(value) >= 1000000) {
    return `$${(value / 1000000).toFixed(1)}M`;
  } else if (Math.abs(value) >= 1000) {
    return `$${(value / 1000).toFixed(1)}K`;
  }
  return `$${value.toFixed(0)}`;
}

function generateDeltaSummary(deltaAnalysis) {
  if (deltaAnalysis.significant_changes.length === 0) {
    return 'No significant metric changes detected';
  }

  const topChanges = deltaAnalysis.significant_changes
    .sort((a, b) => b.significance - a.significance)
    .slice(0, 3)
    .map(change => `${change.metric}: ${change.change}`)
    .join(', ');

  return `Significant changes: ${topChanges}`;
}

